// server/api/routers/user.ts
import { z } from "zod";
import { createTRPCRouter, protectedProcedure, publicProcedure } from "../trpc";
import { TRPCError } from "@trpc/server";

// AI-generated validation schemas
const userProfileSchema = z.object({
  name: z.string().min(2).max(100),
  email: z.string().email(),
  bio: z.string().max(500).optional(),
});

const getUserSchema = z.object({
  userId: z.string().uuid(),
});

export const userRouter = createTRPCRouter({
  // Public query - get user profile
  getProfile: publicProcedure
    .input(getUserSchema)
    .query(async ({ ctx, input }) => {
      const user = await ctx.db.user.findUnique({
        where: { id: input.userId },
        select: {
          id: true,
          name: true,
          email: true,
          bio: true,
          createdAt: true,
          _count: {
            select: {
              posts: true,
              followers: true,
            },
          },
        },
      });

      if (!user) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "User not found",
        });
      }

      return user;
    }),

  // Protected mutation - update profile
  updateProfile: protectedProcedure
    .input(
      z
        .object({
          userId: z.string().uuid(),
        })
        .merge(userProfileSchema),
    )
    .mutation(async ({ ctx, input }) => {
      // Verify user can only update their own profile
      if (ctx.session.user.id !== input.userId) {
        throw new TRPCError({
          code: "FORBIDDEN",
          message: "Cannot update another user's profile",
        });
      }

      const updatedUser = await ctx.db.user.update({
        where: { id: input.userId },
        data: {
          name: input.name,
          email: input.email,
          bio: input.bio,
        },
      });

      return updatedUser;
    }),

  // AI-powered search with fuzzy matching
  searchUsers: publicProcedure
    .input(
      z.object({
        query: z.string().min(1),
        limit: z.number().min(1).max(50).default(10),
      }),
    )
    .query(async ({ ctx, input }) => {
      const users = await ctx.db.$queryRaw`
        SELECT id, name, email, bio,
               similarity(name, ${input.query}) as name_similarity
        FROM users
        WHERE similarity(name, ${input.query}) > 0.3
        ORDER BY name_similarity DESC
        LIMIT ${input.limit}
      `;

      return users;
    }),
});
