// lib/websocket/server.ts
import { WebSocketServer, WebSocket } from "ws";
import { z } from "zod";
import { verifyToken } from "@/lib/auth";

interface Client {
  ws: WebSocket;
  userId: string;
  roomId: string;
}

const clients = new Map<string, Client>();

const messageSchema = z.discriminatedUnion("type", [
  z.object({
    type: z.literal("join"),
    roomId: z.string(),
    token: z.string(),
  }),
  z.object({
    type: z.literal("leave"),
    roomId: z.string(),
  }),
  z.object({
    type: z.literal("typing"),
    roomId: z.string(),
    isTyping: z.boolean(),
  }),
  z.object({
    type: z.literal("message"),
    roomId: z.string(),
    content: z.string(),
  }),
]);

export function setupWebSocketServer(server: any) {
  const wss = new WebSocketServer({ server });

  wss.on("connection", (ws: WebSocket) => {
    let clientId: string | null = null;

    ws.on("message", async (data: Buffer) => {
      try {
        const raw = JSON.parse(data.toString());
        const message = messageSchema.parse(raw);

        switch (message.type) {
          case "join": {
            const user = await verifyToken(message.token);
            if (!user) {
              ws.send(JSON.stringify({ error: "Invalid token" }));
              ws.close();
              return;
            }

            clientId = `${user.id}-${Date.now()}`;
            clients.set(clientId, {
              ws,
              userId: user.id,
              roomId: message.roomId,
            });

            // Broadcast user joined
            broadcastToRoom(
              message.roomId,
              {
                type: "user-joined",
                userId: user.id,
              },
              clientId,
            );

            break;
          }

          case "typing": {
            if (!clientId) return;
            const client = clients.get(clientId);
            if (!client) return;

            broadcastToRoom(
              message.roomId,
              {
                type: "user-typing",
                userId: client.userId,
                isTyping: message.isTyping,
              },
              clientId,
            );
            break;
          }

          case "message": {
            if (!clientId) return;
            const client = clients.get(clientId);
            if (!client) return;

            // AI-powered message moderation could go here
            const moderatedContent = await moderateContent(message.content);

            broadcastToRoom(message.roomId, {
              type: "new-message",
              userId: client.userId,
              content: moderatedContent,
              timestamp: new Date().toISOString(),
            });
            break;
          }

          case "leave": {
            if (!clientId) return;
            handleDisconnect(clientId);
            break;
          }
        }
      } catch (error) {
        console.error("WebSocket error:", error);
        ws.send(JSON.stringify({ error: "Invalid message format" }));
      }
    });

    ws.on("close", () => {
      if (clientId) {
        handleDisconnect(clientId);
      }
    });
  });

  function broadcastToRoom(
    roomId: string,
    message: any,
    excludeClientId?: string,
  ) {
    for (const [id, client] of clients.entries()) {
      if (client.roomId === roomId && id !== excludeClientId) {
        client.ws.send(JSON.stringify(message));
      }
    }
  }

  function handleDisconnect(clientId: string) {
    const client = clients.get(clientId);
    if (client) {
      broadcastToRoom(
        client.roomId,
        {
          type: "user-left",
          userId: client.userId,
        },
        clientId,
      );
      clients.delete(clientId);
    }
  }
}

async function moderateContent(content: string): Promise<string> {
