// lib/stores/editor-store.ts
import { create } from "zustand";
import { persist } from "zustand/middleware";
import { immer } from "zustand/middleware/immer";

interface EditorState {
  content: string;
  title: string;
  tags: string[];
  savedAt: string | null;
  isDirty: boolean;

  // Actions
  setContent: (content: string) => void;
  setTitle: (title: string) => void;
  addTag: (tag: string) => void;
  removeTag: (tag: string) => void;
  markSaved: () => void;
  reset: () => void;
}

const initialState = {
  content: "",
  title: "",
  tags: [],
  savedAt: null,
  isDirty: false,
};

export const useEditorStore = create<EditorState>()(
  persist(
    immer((set) => ({
      ...initialState,

      setContent: (content) =>
        set((state) => {
          state.content = content;
          state.isDirty = true;
        }),

      setTitle: (title) =>
        set((state) => {
          state.title = title;
          state.isDirty = true;
        }),

      addTag: (tag) =>
        set((state) => {
          if (!state.tags.includes(tag)) {
            state.tags.push(tag);
            state.isDirty = true;
          }
        }),

      removeTag: (tag) =>
        set((state) => {
          state.tags = state.tags.filter((t) => t !== tag);
          state.isDirty = true;
        }),

      markSaved: () =>
        set((state) => {
          state.savedAt = new Date().toISOString();
          state.isDirty = false;
        }),

      reset: () => set(initialState),
    })),
    {
      name: "editor-storage",
      partialize: (state) => ({
        content: state.content,
        title: state.title,
        tags: state.tags,
      }),
    },
  ),
);
