  generateStagePrompt(
    subtask: string,
    stageIndex: number,
    totalStages: number,
  ): string {
    const stageContext =
      stageIndex === 0
        ? "You are starting a multi-step analysis."
        : `You are continuing a multi-step analysis. Previous stages have completed ${stageIndex} of ${totalStages} steps.`;

