// Express API testing
const request = require("supertest");
const app = require("../app");
const User = require("../models/User");
const jwt = require("jsonwebtoken");

// Test database setup
const { MongoMemoryServer } = require("mongodb-memory-server");
const mongoose = require("mongoose");

let mongoServer;

beforeAll(async () => {
  mongoServer = await MongoMemoryServer.create();
  const mongoUri = mongoServer.getUri();
  await mongoose.connect(mongoUri);
});

afterAll(async () => {
  await mongoose.disconnect();
  await mongoServer.stop();
});

beforeEach(async () => {
  await User.deleteMany({});
});

describe("User API Endpoints", () => {
  describe("POST /api/users", () => {
    test("creates a new user successfully", async () => {
      const userData = {
        email: "test@example.com",
        password: "securePassword123",
        name: "Test User",
      };

      const response = await request(app)
        .post("/api/users")
        .send(userData)
        .expect(201);

      expect(response.body).toMatchObject({
        user: {
          email: userData.email,
          name: userData.name,
        },
        token: expect.any(String),
      });

      // Verify user was saved to database
      const savedUser = await User.findOne({ email: userData.email });
      expect(savedUser).toBeTruthy();
      expect(savedUser.password).not.toBe(userData.password); // Should be hashed
    });

    test("validates required fields", async () => {
      const invalidData = {
        email: "invalid-email",
        password: "123", // Too short
      };

      const response = await request(app)
        .post("/api/users")
        .send(invalidData)
        .expect(400);

      expect(response.body.errors).toEqual(
        expect.arrayContaining([
          expect.objectContaining({
            field: "email",
            message: "Invalid email format",
          }),
          expect.objectContaining({
            field: "password",
            message: "Password must be at least 8 characters",
          }),
        ]),
      );
    });

    test("prevents duplicate email registration", async () => {
      const userData = {
        email: "test@example.com",
        password: "securePassword123",
        name: "Test User",
      };

      // Create first user
      await request(app).post("/api/users").send(userData).expect(201);

      // Attempt to create duplicate
      const response = await request(app)
        .post("/api/users")
        .send(userData)
        .expect(409);

      expect(response.body.error).toBe("Email already exists");
    });
  });

  describe("GET /api/users/:id", () => {
    let authToken;
    let testUser;

    beforeEach(async () => {
      testUser = await User.create({
        email: "test@example.com",
        password: "hashedPassword",
        name: "Test User",
      });

      authToken = jwt.sign({ userId: testUser._id }, process.env.JWT_SECRET, {
        expiresIn: "1h",
      });
    });

    test("returns user profile for authenticated user", async () => {
      const response = await request(app)
        .get(`/api/users/${testUser._id}`)
        .set("Authorization", `Bearer ${authToken}`)
        .expect(200);

      expect(response.body).toMatchObject({
        id: testUser._id.toString(),
        email: testUser.email,
        name: testUser.name,
      });

      // Should not return sensitive data
      expect(response.body.password).toBeUndefined();
    });

    test("returns 401 for unauthenticated requests", async () => {
      await request(app).get(`/api/users/${testUser._id}`).expect(401);
    });

    test("returns 403 for unauthorized access", async () => {
      const otherUser = await User.create({
        email: "other@example.com",
        password: "hashedPassword",
        name: "Other User",
      });

      await request(app)
        .get(`/api/users/${otherUser._id}`)
        .set("Authorization", `Bearer ${authToken}`)
        .expect(403);
    });
  });
});
